const rows = $input.all();
let properties = '';

for (let i = 0; i < rows.length; i++) {
  const d = rows[i].json;
  properties += '[ID: ' + d.ID + '] ' + d['Property Name'] + '\n';
  properties += 'Location: ' + d.Location + '\n';
  properties += 'Price: LKR ' + d['Price (LKR)'] + '\n';
  properties += 'Rooms: ' + d.Rooms + '\n';
  properties += 'Land: ' + d['Land Size (Perches)'] + ' perches\n';
  properties += 'Legal: ' + d['Legal Status'] + '\n';
  properties += 'GPS: ' + d['GPS Coordinates'] + '\n';
  properties += '---\n';
}

const chatInput = $('When chat message received').first().json.chatInput;

return [{ json: { properties: properties, chatInput: chatInput } }];
